SELECT hse_band_gap_eV
FROM electronic_properties
WHERE material_id = 0;

SELECT researcher_name
FROM researchers
WHERE researcher_id IN (
  SELECT DISTINCT researcher_id
  FROM materials
);

SELECT material_name
FROM materials
ORDER BY material_name;

SELECT pocket_1e18
FROM pocket_densities
WHERE material_id = 1;

SELECT COUNT(DISTINCT user_id) AS total_unique_users
FROM material_access
WHERE access_date >= DATE('now', '-30 days');

SELECT average_me
FROM electronic_mobilities
WHERE material_id = 1;

SELECT user_id, access_type
FROM material_access
WHERE material_id = 1;
